module RefModule (  
    input clk,  
    input rst,  
    input en,  
    input d,  
    output reg q  
);  
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or posedge rst) begin  
        if (rst)  
            q <= 0;  
        else if (en)  
            q <= d;  
    end  
endmodule
